import React from "react";
import { useQuery } from "@tanstack/react-query";
import Loading from "../Loading/Loading.jsx";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/effect-fade";
import "swiper/css/navigation";
import "swiper/css/pagination";
import "./ProductsDetails.css";
import {
  Autoplay,
  EffectCoverflow,
  Navigation,
  Pagination,
} from "swiper/modules";
import { useParams } from "react-router-dom";
import { useEffect } from "react";


function parseNestedJson(jsonString) {
  try {
    const parsedObject = JSON.parse(jsonString);

    // Recursively parse nested JSON strings
    for (const key in parsedObject) {
      if (typeof parsedObject[key] === 'string') {
        try {
          parsedObject[key] = JSON.parse(parsedObject[key]);
        } catch (error) {
          // Handle parsing errors, e.g., log the error or return the original string
          console.error(`Error parsing nested JSON: ${error.message}`);
        }
      }
    }

    return parsedObject;
  } catch (error) {
    console.error(`Error parsing JSON: ${error.message}`);
    return null;
  }
}



function ProductsDetails({ images }) {


  const { data, isLoading, isSuccess, error } = useQuery({
    queryKey: ["details"],
    queryFn: () => fetch("http://127.0.0.1:8000/api/ProductDetails/1").then((res) => res.json()),
  });

  const { ProductId } = useParams();

  return (
    <>
    {isSuccess && <div  className="hugy-body">
      
      <div
      className="border-container"
    >
      <h1  className="gg">
        {images[ProductId].title}
      </h1>
<Swiper
  className="pd-swiper"
  effect={"coverflow"}
  grabCursor={true}
  centeredSlides={true}
  slidesPerView={"auto"}
  coverflowEffect={{
    rotate: 50,
    stretch: 0,
    depth: 100,
    modifier: 1,
    slideShadows: false,
  }}
  navigation={true}
  autoplay={{
    delay: 3000,
  }}
  rewind={true}
  spaceBetween={10}
  pagination={{
    clickable: true,
    type: "bullets",
  }}
  modules={[EffectCoverflow, Pagination, Navigation, Autoplay]}
>
  {/* Loop through each product */}
  {data.map((item, index) => {
    const parsedImages = parseNestedJson(item.product_images).images; // Parse the images
    return parsedImages.slice(1).map((image, imgIndex) => ( // Skip the first image
      <SwiperSlide key={`${index}-${imgIndex}`} className="pd-swiper-slide">
        <img src={image} alt={`Slide ${imgIndex + 1}`} />
      </SwiperSlide>
    ));
  })}
</Swiper>
      <div className="background-hugy">
      <section className="products-details-section">
        <p
          className="products-details-text-title"
        >
          Product Description
        </p>
        <p
          className="products-details-text-info"

        >
          {images[ProductId].description}
        </p>
        <p
          className="products-details-text-title"

        >
          Product ingredients
        </p>
        <p
          className="products-details-text-info"

        >
          {images[ProductId].ingredients}
        </p>
        <p
          className="products-details-text-title"

        >
          Weight
        </p>
        <p
          className="products-details-text-info"

        >
          {images[ProductId].weight}
        </p>
        <p
          className="products-details-text-title"

        >
          Packing
        </p>
        <p
          className="products-details-text-info"

        >
          {images[ProductId].packing}
        </p>
      </section>
      </div>
    </div>
 
    </div>
    }
    {isLoading && <Loading />}
   </>
  );
}

export default ProductsDetails;
